// ============================================
// MODAL OVERLAY COMPONENT
// ============================================

export interface ModalOverlayProps
  extends React.ComponentPropsWithoutRef<typeof DialogPrimitive.Overlay>,
    VariantProps<typeof modalOverlayVariants> {}

const ModalOverlay = React.forwardRef<
  React.ElementRef<typeof DialogPrimitive.Overlay>,
  ModalOverlayProps
>(({ className, variant, ...props }, ref) => (
  <DialogPrimitive.Overlay
    ref={ref}
    className={cn(
      modalOverlayVariants({ variant }),
      "data-[state=open]:animate-in data-[state=closed]:animate-out",
      "data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0",
      className
    )}
    {...props}
  />
));
ModalOverlay.displayName = DialogPrimitive.Overlay.displayName;

// ============================================
// MODAL CONTENT COMPONENT
// ============================================

export interface ModalContentProps
  extends React.ComponentPropsWithoutRef<typeof DialogPrimitive.Content>,
    VariantProps<typeof modalContentVariants> {
  /**
   * Show close button in top right corner
   */
  showCloseButton?: boolean;

  /**
   * Overlay variant
   */
  overlayVariant?: VariantProps<typeof modalOverlayVariants>["variant"];

  /**
   * Prevent closing on overlay click
   */
  preventOverlayClose?: boolean;

  /**
   * Prevent closing on escape key
   */
  preventEscapeClose?: boolean;
}

const ModalContent = React.forwardRef<
  React.ElementRef<typeof DialogPrimitive.Content>,
  ModalContentProps
>(
  (
    {
      className,
      children,
      size,
      showCloseButton = true,
      overlayVariant = "default",
      preventOverlayClose = false,
      preventEscapeClose = false,
      onPointerDownOutside,
      onEscapeKeyDown,
      ...props
    },
    ref
  ) => {
    const handlePointerDownOutside = (e: Event) => {
      if (preventOverlayClose) {
        e.preventDefault();
      }
      onPointerDownOutside?.(e as any);
    };

    const handleEscapeKeyDown = (e: KeyboardEvent) => {
      if (preventEscapeClose) {
        e.preventDefault();
      }
      onEscapeKeyDown?.(e);
    };

    return (
      <ModalPortal>
        <ModalOverlay variant={overlayVariant} />
        <DialogPrimitive.Content
          ref={ref}
          onPointerDownOutside={handlePointerDownOutside}
          onEscapeKeyDown={handleEscapeKeyDown}
          className={cn(modalContentVariants({ size }), className)}
          {...props}
        >
          {children}

          {/* Close button */}
          {showCloseButton && (
            <DialogPrimitive.Close
              className={cn(
                "absolute right-4 top-4",
                "rounded-sm opacity-70",
                "ring-offset-background",
                "transition-opacity",
                "hover:opacity-100",
                "focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2",
                "disabled:pointer-events-none",
                "data-[state=open]:bg-accent data-[state=open]:text-muted-foreground"
              )}
              aria-label="Close"
            >
              <X className="h-4 w-4" />
            </DialogPrimitive.Close>
          )}
        </DialogPrimitive.Content>
      </ModalPortal>
    );
  }
);
ModalContent.displayName = DialogPrimitive.Content.displayName;

