export interface AlertModalProps {
  /**
   * Modal open state
   */
  open: boolean;

  /**
   * Callback when modal state changes
   */
  onOpenChange: (open: boolean) => void;

  /**
   * Alert type
   */
  type?: "info" | "success" | "warning" | "error";

  /**
   * Modal title
   */
  title: string;

  /**
   * Modal description/message
   */
  description: string;

  /**
   * Confirm button text
   */
  confirmText?: string;

  /**
   * Cancel button text
   */
  cancelText?: string;

  /**
   * Callback when confirm is clicked
   */
  onConfirm?: () => void;

  /**
   * Callback when cancel is clicked
   */
  onCancel?: () => void;

  /**
   * Show cancel button
   */
  showCancel?: boolean;

  /**
   * Loading state for confirm button
   */
  isLoading?: boolean;
}

/**
 * AlertModal Component
 *
 * Pre-configured modal for alerts, confirmations, and notifications.
 *
 * @example
 * <AlertModal
 *   open={isOpen}
 *   onOpenChange={setIsOpen}
 *   type="warning"
 *   title="Delete Item?"
 *   description="This action cannot be undone."
 *   confirmText="Delete"
 *   onConfirm={handleDelete}
 *   showCancel
 * />
 */
const AlertModal: React.FC<AlertModalProps> = ({
  open,
  onOpenChange,
  type = "info",
  title,
  description,
  confirmText = "OK",
  cancelText = "Cancel",
  onConfirm,
  onCancel,
  showCancel = false,
  isLoading = false,
}) => {
  const icons = {
    info: <Info className="h-6 w-6 text-blue-500" />,
    success: <CheckCircle className="h-6 w-6 text-green-500" />,
    warning: <AlertTriangle className="h-6 w-6 text-amber-500" />,
    error: <AlertCircle className="h-6 w-6 text-red-500" />,
  };

  const confirmVariants = {
    info: "default" as const,
    success: "success" as const,
    warning: "warning" as const,
    error: "destructive" as const,
  };

  const handleConfirm = () => {
    onConfirm?.();
    if (!isLoading) {
      onOpenChange(false);
    }
  };

  const handleCancel = () => {
    onCancel?.();
    onOpenChange(false);
  };

  return (
    <Modal open={open} onOpenChange={onOpenChange}>
      <ModalContent size="sm" showCloseButton={false}>
        <ModalHeader>
          <div className="flex items-center gap-3">
            {icons[type]}
            <ModalTitle>{title}</ModalTitle>
          </div>
          <ModalDescription className="pl-9">{description}</ModalDescription>
        </ModalHeader>
        <ModalFooter>
          {showCancel && (
            <Button variant="outline" onClick={handleCancel} disabled={isLoading}>
              {cancelText}
            </Button>
          )}
          <Button
            variant={confirmVariants[type]}
            onClick={handleConfirm}
            isLoading={isLoading}
          >
            {confirmText}
          </Button>
        </ModalFooter>
      </ModalContent>
    </Modal>
  );
};
AlertModal.displayName = "AlertModal";

// ============================================
// CONFIRM MODAL COMPONENT
// ============================================

export interface ConfirmModalProps {
  /**
   * Modal open state
   */
  open: boolean;

  /**
   * Callback when modal state changes
   */
  onOpenChange: (open: boolean) => void;

  /**
   * Modal title
   */
  title: string;

  /**
   * Modal description/message
   */
  description: string;

  /**
   * Confirm button text
   */
  confirmText?: string;

  /**
   * Cancel button text
   */
  cancelText?: string;

  /**
   * Callback when confirm is clicked
   */
  onConfirm: () => void | Promise<void>;

  /**
   * Destructive action (red confirm button)
   */
  destructive?: boolean;
}

/**
 * ConfirmModal Component
 *
 * Simple confirmation dialog with confirm/cancel actions.
 *
 * @example
 * <ConfirmModal
 *   open={isOpen}
 *   onOpenChange={setIsOpen}
 *   title="Delete Product?"
 *   description="This will permanently delete the product."
 *   onConfirm={handleDelete}
 *   destructive
 * />
 */
const ConfirmModal: React.FC<ConfirmModalProps> = ({
  open,
  onOpenChange,
  title,
  description,
  confirmText = "Confirm",
  cancelText = "Cancel",
  onConfirm,
  destructive = false,
}) => {
  const [isLoading, setIsLoading] = React.useState(false);

  const handleConfirm = async () => {
    setIsLoading(true);
    try {
      await onConfirm();
      onOpenChange(false);
    } catch (error) {
      console.error("Confirm action failed:", error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Modal open={open} onOpenChange={onOpenChange}>
      <ModalContent size="sm">
        <ModalHeader>
          <ModalTitle>{title}</ModalTitle>
          <ModalDescription>{description}</ModalDescription>
        </ModalHeader>
        <ModalFooter>
          <Button
            variant="outline"
            onClick={() => onOpenChange(false)}
            disabled={isLoading}
          >
            {cancelText}
          </Button>
          <Button
            variant={destructive ? "destructive" : "default"}
            onClick={handleConfirm}
            isLoading={isLoading}
          >
            {confirmText}
          </Button>
        </ModalFooter>
      </ModalContent>
    </Modal>
  );
};
ConfirmModal.displayName = "ConfirmModal";

